args.sparql:
SELECT (YEAR(?dob) AS ?yearOfBirth) ?lastName WHERE {
  ?event wdt:P150 wd:Q2753286 ;
         wdt:P585 ?date .
  FILTER (YEAR(?date) = 2002)
  ?event wdt:P174 ?player .
  ?player wdt:P569 ?dob .
  ?player wdt:P734 ?lastName .
}
ORDER BY ASC(YEAR(?dob)) ASC(?lastName)
LIMIT 6

